  import org.apache.log4j.Logger;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import java.text.SimpleDateFormat;
import java.util.Date;

  Logger logger = Logger.getLogger("sailpoint.ascension.rules.cube.peoplesoft.type");
  
  if(link !=null){
		String hireDate = link.getAttribute("HIRE_DT");
    
    if (Util.isNotNullOrEmpty(hireDate))
    {
    
    Date dateObject = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a zzz").parse(hireDate);
    
    //MM-dd-yyyy HH:mm:ss.SSSSSX
    
    
    String dateNewFormat = new SimpleDateFormat("yyyy-MM-dd").format(dateObject);
    
    return dateNewFormat;
      
    }
  }
  
return null;
